#include <iostream>
#include <string>
#include <vector>
#include <stack>
#include <sstream>
using namespace std;

const int MAXN = 100010;

string s;
int n, q;
int val[MAXN];
bool important[MAXN];

struct Node {
    int type; // 0: 变量, 1: 与, 2: 或, 3: 非
    int value;
    int var_id;
    int left = -1, right = -1;
};

vector<Node> nodes;
vector<int> var_node;

// 构建表达式树
void build() {
    stack<int> st;
    stringstream ss(s);
    string token;

    while (ss >> token) {
        if (token == "&") {
            int r = st.top(); st.pop();
            int l = st.top(); st.pop();
            Node node;
            node.type = 1;
            node.left = l;
            node.right = r;
            node.value = nodes[l].value & nodes[r].value;
            node.var_id = -1;
            nodes.push_back(node);
            st.push(nodes.size() - 1);
        } else if (token == "|") {
            int r = st.top(); st.pop();
            int l = st.top(); st.pop();
            Node node;
            node.type = 2;
            node.left = l;
            node.right = r;
            node.value = nodes[l].value | nodes[r].value;
            node.var_id = -1;
            nodes.push_back(node);
            st.push(nodes.size() - 1);
        } else if (token == "!") {
            int child = st.top(); st.pop();
            Node node;
            node.type = 3;
            node.left = child;
            node.value = !nodes[child].value;
            node.var_id = -1;
            nodes.push_back(node);
            st.push(nodes.size() - 1);
        } else {
            // 变量
            int id = stoi(token.substr(1));
            Node node;
            node.type = 0;
            node.var_id = id;
            node.value = val[id];
            nodes.push_back(node);
            var_node[id] = nodes.size() - 1;
            st.push(nodes.size() - 1);
        }
    }
}

// 标记重要节点
void mark_important(int u) {
    Node& node = nodes[u];

    if (node.type == 0) {
        important[node.var_id] = true;
        return;
    }

    if (node.type == 1) { // AND
        int l = node.left, r = node.right;
        if (node.value == 1) {
            mark_important(l);
            mark_important(r);
        } else {
            if (nodes[l].value == 0 && nodes[r].value == 1) {
                mark_important(l);
            } else if (nodes[l].value == 1 && nodes[r].value == 0) {
                mark_important(r);
            } else if (nodes[l].value == 0 && nodes[r].value == 0) {
                // 都不重要
            }
        }
    } else if (node.type == 2) { // OR
        int l = node.left, r = node.right;
        if (node.value == 0) {
            mark_important(l);
            mark_important(r);
        } else {
            if (nodes[l].value == 1 && nodes[r].value == 0) {
                mark_important(l);
            } else if (nodes[l].value == 0 && nodes[r].value == 1) {
                mark_important(r);
            } else if (nodes[l].value == 1 && nodes[r].value == 1) {
                // 都不重要
            }
        }
    } else if (node.type == 3) { // NOT
        mark_important(node.left);
    }
}

int main() {
    getline(cin, s);
    cin >> n;
    var_node.resize(n + 1);

    for (int i = 1; i <= n; i++) {
        cin >> val[i];
    }

    build();
    int root = nodes.size() - 1;
    int result = nodes[root].value;

    mark_important(root);

    cin >> q;
    while (q--) {
        int x;
        cin >> x;
        if (important[x]) {
            cout << (1 - result) << endl;
        } else {
            cout << result << endl;
        }
    }

    return 0;
}
